PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS `orders` (
	`id` text PRIMARY KEY NOT NULL,
	`buyer_id` text NOT NULL,
	`tier_id` text NOT NULL,
	`total_amount` integer NOT NULL,
	`status` text NOT NULL,
	`rejection_reason` text, `created_at` integer NOT NULL, `admin_notes` text, `created_by` text, `buyer_note` text,
	FOREIGN KEY (`buyer_id`) REFERENCES `users`(`id`) ON UPDATE no action ON DELETE no action,
	FOREIGN KEY (`tier_id`) REFERENCES `tiers`(`id`) ON UPDATE no action ON DELETE no action
);
CREATE TABLE IF NOT EXISTS `products` (
	`id` text PRIMARY KEY NOT NULL,
	`name` text NOT NULL,
	`sku` text NOT NULL,
	`base_price` integer NOT NULL
, `image_url` text, `stock` integer DEFAULT 0 NOT NULL, `unit` text DEFAULT 'Pcs' NOT NULL, "created_at" integer, `deleted_at` integer);
CREATE TABLE IF NOT EXISTS `tier_prices` (
	`id` text PRIMARY KEY NOT NULL,
	`product_id` text NOT NULL,
	`tier_id` text NOT NULL,
	"price" integer, `is_active` integer DEFAULT true NOT NULL,
	FOREIGN KEY (`product_id`) REFERENCES `products`(`id`) ON UPDATE no action ON DELETE no action,
	FOREIGN KEY (`tier_id`) REFERENCES `tiers`(`id`) ON UPDATE no action ON DELETE no action
);
CREATE TABLE IF NOT EXISTS `tiers` (
	`id` text PRIMARY KEY NOT NULL,
	`name` text NOT NULL
);
CREATE TABLE IF NOT EXISTS `users` (
	`id` text PRIMARY KEY NOT NULL,
	`username` text NOT NULL,
	`phone` text NOT NULL,
	`password` text NOT NULL,
	`role` text NOT NULL,
	`tier_id` text,
	`branch_name` text, `created_by` text, `is_active` integer DEFAULT true NOT NULL, `has_completed_tour` integer DEFAULT false NOT NULL,
	FOREIGN KEY (`tier_id`) REFERENCES `tiers`(`id`) ON UPDATE no action ON DELETE no action
);
CREATE TABLE IF NOT EXISTS `order_items` (
	`id` text PRIMARY KEY NOT NULL,
	`order_id` text NOT NULL,
	`product_id` text NOT NULL,
	`quantity` integer NOT NULL,
	`price_at_purchase` integer NOT NULL,
	FOREIGN KEY (`order_id`) REFERENCES `orders`(`id`) ON UPDATE no action ON DELETE no action,
	FOREIGN KEY (`product_id`) REFERENCES `products`(`id`) ON UPDATE no action ON DELETE no action
);
CREATE UNIQUE INDEX `products_sku_unique` ON `products` (`sku`);
CREATE UNIQUE INDEX `tiers_name_unique` ON `tiers` (`name`);
CREATE UNIQUE INDEX `users_username_unique` ON `users` (`username`);
CREATE UNIQUE INDEX `users_phone_unique` ON `users` (`phone`);
CREATE INDEX `status_idx` ON `orders` (`status`);
CREATE INDEX `created_at_idx` ON `orders` (`created_at`);
CREATE INDEX `created_by_idx` ON `users` (`created_by`);
CREATE INDEX `deleted_at_idx` ON `products` (`deleted_at`);
CREATE INDEX `buyer_status_idx` ON `orders` (`buyer_id`,`status`);
CREATE INDEX `product_tier_idx` ON `tier_prices` (`product_id`,`tier_id`);
CREATE INDEX `tier_idx` ON `tier_prices` (`tier_id`);
CREATE INDEX `order_idx` ON `order_items` (`order_id`);
CREATE INDEX `product_idx` ON `order_items` (`product_id`);
COMMIT;
